"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3198"],{66286(e,i,r){r.r(i),r.d(i,{default:()=>n});var a=r(74848),o=r(47643),t=JSON.parse('{"id":120,"it":{"title":"Pratica del dialogo in inglese","prompt":"I want you to act as a spoken English teacher and improver. I will speak to you in English and you will reply to me in English to practice my spoken English. I want you to keep your reply neat, limiting the reply to 100 words. I want you to strictly correct my grammar mistakes, typos, and factual errors. I want you to ask me a question in your reply. Now let\'s start practicing, you could ask me a question first. Remember, I want you to strictly correct my grammar mistakes, typos, and factual errors.","description":"Voglio che tu agisca come insegnante e miglioratore della lingua inglese. Io ti parler\xf2 in inglese e tu mi risponderai in inglese per esercitare il mio inglese parlato. Vorrei che le tue risposte fossero ordinate e che limitassi le tue risposte a 100 parole o meno. Vorrei che correggessi rigorosamente i miei errori grammaticali, i refusi e gli errori di fatto. Vorrei che nella vostra risposta mi faceste una domanda. Ora iniziamo l\'esercizio e potete iniziare facendomi una domanda. Ricorda, voglio che tu corregga rigorosamente i miei errori grammaticali, i refusi e gli errori di fatto.","remark":"Per i dialoghi di conversazione in inglese, le risposte saranno limitate a 100 parole. Saranno corretti gli errori grammaticali, gli errori di battitura e gli errori di fatto presenti nell\'input."},"tags":["pedagogy"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-spoken-english-teacher-and-improver","count":2476,"related":[{"id":200,"title":"Titolo: Saggio sulla scuola secondaria di primo grado","remark":"Dopo aver eseguito questo prompt, digitate \\"Converti questi in un saggio\\" per vedere se il saggio funziona meglio. Contributo di @Qizhen-Yang."},{"id":182,"title":"Quadrupla induzione strutturale","remark":"Un riassunto a pi\xf9 livelli dell\'articolo viene sintetizzato e pu\xf2 essere utilizzato anche per spiegare parole e frasi e fare associazioni. Contributo di @ergf991. (C\'\xe8 una grande differenza tra la versione inglese e quella cinese di questo prompt, per favore cambiate lingua se dovete usare la versione inglese)."},{"id":265,"title":"Insegnante privato","remark":"Contributo di @EmmmmmmaWWWWW."}],"metaTitle":"Coach Inglese: Pratica Orale","metaDescription":"Migliorare il parlato? Chatta in inglese, correzioni rigide. Pratica conversazione con domande per fluidit\xe0. Provalo ora.","faq":[{"q":"L\'AI riconosce il mio \\"italiano inglesizzato\\"?","a":"Per espressioni tipiche da traduzione letterale (very nice to meet you come calco di \xabmolto piacere di conoscerti\xbb) riconosce e corregge; anche errori sottili su articoli e tempi verbali vengono segnalati. Ma non sente la tua pronuncia perch\xe9 \xe8 testuale: per la pronuncia serve un prodotto vocale."},{"q":"Il limite di 100 parole \xe8 troppo breve, come approfondire?","a":"Sostituisci \xab100 words\xbb con la lunghezza desiderata, ma non oltre 250: risposte pi\xf9 lunghe diventano discorsi e perdono ritmo conversazionale. Per approfondire preferisci pi\xf9 turni da 100-150 parole, pi\xf9 vicini al dialogo reale."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,a.jsx)(o.A,{prompt:t,currentLanguage:"it"})}}}]);